arguments.file_text:
// Test stackalloc with native-sized integer types (nint / nuint)

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");

// stackalloc Span<nint>
Span<nint> signedSpan = stackalloc nint[4];
for (int i = 0; i < signedSpan.Length; i++)
    signedSpan[i] = (nint)(i * 10);

Console.WriteLine("\nSpan<nint> via stackalloc:");
foreach (var val in signedSpan)
    Console.WriteLine($"  {val}");

// stackalloc Span<nuint>
Span<nuint> unsignedSpan = stackalloc nuint[4];
for (int i = 0; i < unsignedSpan.Length; i++)
    unsignedSpan[i] = (nuint)(i * 100);

Console.WriteLine("\nSpan<nuint> via stackalloc:");
foreach (var val in unsignedSpan)
    Console.WriteLine($"  {val}");

Console.WriteLine("\nSuccess — stackalloc works with both nint and nuint.");

